// ====================================================
// LIFE OS — CONFIGURATIE
// Vul hieronder jouw eigen waarden in
// ====================================================

// 1. Notion Integration Token
//    Maak aan via: notion.so/my-integrations
//    Voeg de integratie toe aan je Life Management pagina
const NOTION_TOKEN = 'secret_JOUW_NOTION_TOKEN';

// 2. Anthropic API Key
//    Maak aan via: console.anthropic.com
const ANTHROPIC_KEY = 'sk-ant-JOUW_ANTHROPIC_KEY';

// 3. Notion Database IDs
//    Kopieer de ID uit de URL van elke database:
//    notion.so/workspace/PAGINA-TITLE-{DIT_IS_HET_ID}
const DB_DAILY_CHECKINS  = 'ebcc855d-5b66-424d-be78-e8a146587572'; // 📋 Daily Check-ins
const DB_FINANCE_MONTHLY = 'FINANCE_MONTHLY_DB_ID';                // Finance maandoverzicht
const DB_NEEDLE_MOVERS   = 'a8196c3b-f0fc-4009-ba7b-82a4e15fef1b'; // 🎯 Needle Movers

// 4. Notion Pagina ID voor de briefing
//    Dit is de 'Life Management' pagina
const BRIEFING_PARENT_PAGE_ID = '11f2a868d6bc8065a00ffcc1317ec147';

// 5. Supabase (optioneel — laat leeg als je geen Supabase hebt)
//    Gebruik de SERVICE ROLE key (niet de anon key) voor schrijfrechten
const SUPABASE_URL         = 'https://JOUW_PROJECT.supabase.co';
const SUPABASE_SERVICE_KEY = 'eyJhbGci_JOUW_SERVICE_ROLE_KEY';

// ── Datum berekeningen ──────────────────────────────
const now = new Date();
const today = now.toISOString().slice(0, 10);
const sevenDaysAgo = new Date(now - 7 * 86400000).toISOString().slice(0, 10);
const firstOfMonth = today.slice(0, 8) + '01';

const d = new Date(Date.UTC(now.getFullYear(), now.getMonth(), now.getDate()));
d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
const weekNo = Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
const weekLabel = `Week ${weekNo} — ${now.toLocaleDateString('nl-NL', { day: 'numeric', month: 'long', year: 'numeric' })}`;
const briefingTitle = `Weekbriefing ${weekLabel}`;

return [{ json: {
  notion_token:     NOTION_TOKEN,
  anthropic_key:    ANTHROPIC_KEY,
  db_checkins:      DB_DAILY_CHECKINS,
  db_finance:       DB_FINANCE_MONTHLY,
  db_needle_movers: DB_NEEDLE_MOVERS,
  briefing_parent:     BRIEFING_PARENT_PAGE_ID,
  supabase_url:        SUPABASE_URL,
  supabase_service_key:SUPABASE_SERVICE_KEY,
  today,
  seven_days_ago:   sevenDaysAgo,
  first_of_month:   firstOfMonth,
  week_no:          weekNo,
  week_label:       weekLabel,
  briefing_title:   briefingTitle
}}];

// Haal ruwe data op uit vorige nodes
const cfg           = $('⚙ Config').item.json;
const checkins      = $('Haal check-ins op').item.json?.results       || [];
const finance       = $('Haal finance op').item.json?.results         || [];
const needleMovers  = $('Haal needle movers op').item.json?.results   || [];

// ── Needle movers extraheren ───────────────────────
const nmList = needleMovers.map(p => {
  const props = p.properties || {};
  return {
    move:   props.Move?.title?.[0]?.plain_text || '',
    nu:     props.Nu?.rich_text?.[0]?.plain_text || '',
    target: props.Target?.rich_text?.[0]?.plain_text || '',
    deadline: props.Deadline?.date?.start || ''
  };
}).filter(m => m.move);

// ── Life check-ins aggregeren ──────────────────────
let energySum = 0, focusSum = 0, moodSum = 0, count = 0;
const wins = [], blockers = [];

checkins.forEach(p => {
  const props = p.properties || {};
  const e = props.Energie?.number;
  const f = props.Focus?.number;
  const m = props.Stemming?.number;
  if (e) { energySum += e; count++; }
  if (f) focusSum += f;
  if (m) moodSum += m;
  (props.Wins?.rich_text || []).forEach(t => { if (t.plain_text) wins.push(t.plain_text); });
  (props.Blokkades?.rich_text || []).forEach(t => { if (t.plain_text) blockers.push(t.plain_text); });
});

const lifeData = count > 0 ? {
  check_ins: count,
  energie_gem: (energySum / count).toFixed(1),
  focus_gem:   (focusSum  / count).toFixed(1),
  stemming_gem:(moodSum   / count).toFixed(1),
  wins:      [...new Set(wins)].slice(0, 5),
  blokkades: [...new Set(blockers)].slice(0, 3)
} : { check_ins: 0, opmerking: 'Geen check-ins gevonden voor deze periode.' };

// ── Finance data extraheren ────────────────────────
let financeData = { opmerking: 'Geen finance data gevonden.' };
if (finance.length > 0) {
  const props = finance[0].properties || {};
  financeData = {
    maand: props.Month?.date?.start || cfg.first_of_month,
    omzet: props.Revenue?.number || props.Omzet?.number || null,
    uitgaven: props.Expenses?.number || props.Uitgaven?.number || null,
    winst: props.Profit?.formula?.number || props.Winst?.number || null,
    nettovermogen: props['Net Worth']?.number || props.Nettovermogen?.number || null
  };
}

// ── Claude prompt bouwen ──────────────────────────
const prompt = `Je bent de persoonlijke business & life coach van Ruben.
Hier zijn de data van afgelopen week (${cfg.week_label}).
Schrijf een beknopte, directe weekbriefing in het Nederlands. Max 350 woorden.

Structuur (gebruik ** voor vetgedrukte koppen):
1. **Top 3 prioriteiten komende week** — actiegericht, met concrete getallen
2. **Wat goed gaat** — max 3 bullets met →
3. **Let op** — max 2 punten, alleen echte risico's
4. **Finance signaal** — 1 zin met de meest relevante getal
5. **Eén heldere actie** — specifiek en meetbaar

Wees direct. Geen introductie, geen afsluiting. Alleen de vijf secties.

## Leven & Persoonlijk
${JSON.stringify(lifeData, null, 2)}

## Finance (${financeData.maand || 'huidige maand'})
${JSON.stringify(financeData, null, 2)}

## 🎯 Huidige Needle Movers (PRIORITEIT — bouw je briefing hieromheen)
${nmList.length > 0 ? nmList.map(m => `- ${m.move} | Nu: ${m.nu} → Target: ${m.target} | Deadline: ${m.deadline}`).join('\n') : 'Geen actieve needle movers gevonden.'}

Vraag jezelf bij elk punt af: beweegt dit de naald op een van bovenstaande moves?

## Leven & Persoonlijk
${JSON.stringify(lifeData, null, 2)}

## Finance (${financeData.maand || 'huidige maand'})
${JSON.stringify(financeData, null, 2)}

## Context
- Bedrijven: Reck-It (vakantie parken, primaire business), Bolshippers (logistics), KR Makler (vakantie vastgoed), Trading, Virtual Assistance
- Reck-It draait geautomatiseerde Meta advertenties via PipeDrive. CPL en salesfunnel zijn de sleutelmetrics.
- Bolshippers heeft cashflow als risicopunt.
- Trading is niet de primaire focus — alleen signaleren bij grote afwijkingen.`;

return [{ json: {
  prompt,
  anthropic_key: cfg.anthropic_key,
  notion_token:  cfg.notion_token,
  briefing_parent: cfg.briefing_parent,
  briefing_title:  cfg.briefing_title,
  week_label:    cfg.week_label,
  life_data:     lifeData,
  finance_data:  financeData
}}];

const response = $input.item.json;
const buildCtx = $('Bouw Claude prompt').item.json;

// Haal tekst op uit Claude response
const briefingText = response?.content?.[0]?.text || 'Briefing kon niet worden gegenereerd.';

// Bouw Notion page blocks van de briefing tekst
// Splits op lege regels voor aparte paragraphen
const paragraphs = briefingText.split(/\n\n+/).filter(p => p.trim());

const notionBlocks = paragraphs.map(para => ({
  object: 'block',
  type: 'paragraph',
  paragraph: {
    rich_text: [{
      type: 'text',
      text: { content: para.trim().slice(0, 2000) },
      annotations: { bold: false, italic: false, code: false, color: 'default' }
    }]
  }
}));

// Voeg datum header toe bovenaan
notionBlocks.unshift({
  object: 'block',
  type: 'callout',
  callout: {
    rich_text: [{ type: 'text', text: { content: `Automatisch gegenereerd op ${new Date().toLocaleDateString('nl-NL', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })} om ${new Date().toLocaleTimeString('nl-NL', { hour: '2-digit', minute: '2-digit' })} via n8n + Claude` } }],
    icon: { emoji: '🧠' },
    color: 'blue_background'
  }
});

return [{ json: {
  briefing_text:   briefingText,
  notion_blocks:   notionBlocks,
  notion_token:    buildCtx.notion_token,
  briefing_parent: buildCtx.briefing_parent,
  briefing_title:  buildCtx.briefing_title
}}];
